import React, { useState } from 'react';
import { Send, Globe } from 'lucide-react';
import { ViewType } from '../App';

interface HeroProps {
  navigateTo: (view: ViewType, query?: string) => void;
}

const Hero: React.FC<HeroProps> = ({ navigateTo }) => {
  const [destination, setDestination] = useState('');

  const handleStartPlanning = (e: React.FormEvent) => {
    e.preventDefault();
    if (destination.trim()) {
      navigateTo('planner', destination.trim());
    }
  };

  return (
    <section className="pt-24 pb-12 md:pt-40 md:pb-24 hero-gradient relative overflow-hidden">
      <div className="absolute top-10 left-1/2 -translate-x-1/2 w-[600px] h-[300px] bg-indigo-500/10 dark:bg-indigo-400/5 blur-[100px] rounded-full -z-10"></div>

      <div className="container mx-auto px-4 text-center relative z-10">
        <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full bg-slate-100 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-400 text-[10px] font-bold mb-6 tracking-wider">
          <Globe className="w-3 h-3 text-indigo-500" />
          <span>JOIN 25,000+ EXPLORERS</span>
        </div>

        <h1 className="text-4xl md:text-7xl font-black tracking-tight text-slate-900 dark:text-white mb-6 leading-[1.1] max-w-4xl mx-auto">
          Travel Smarter. <br/>
          <span className="gradient-text">AI Co-pilot</span> Included.
        </h1>

        <p className="text-base md:text-xl text-slate-500 dark:text-slate-400 mb-8 max-w-xl mx-auto leading-relaxed font-medium">
          Say goodbye to static lists. YourTripy builds logical, flexible itineraries in seconds.
        </p>

        <form onSubmit={handleStartPlanning} className="max-w-xl mx-auto mb-16">
          <div className="relative group">
            <div className="absolute -inset-0.5 bg-gradient-to-r from-indigo-500 to-purple-600 rounded-2xl blur opacity-20 group-focus-within:opacity-40 transition duration-500"></div>
            <div className="relative flex items-center bg-white dark:bg-slate-900 rounded-2xl p-1 border border-slate-200 dark:border-slate-800 shadow-lg">
              <input 
                type="text" 
                placeholder="4 days in Paris for an architect"
                className="flex-grow px-5 py-3.5 bg-transparent outline-none text-slate-900 dark:text-white text-sm font-medium placeholder:text-slate-400"
                value={destination}
                onChange={(e) => setDestination(e.target.value)}
              />
              <button 
                type="submit"
                className="px-5 py-3.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl font-bold flex items-center gap-2 transition-all shadow-md outline-none"
              >
                Plan <Send className="w-3.5 h-3.5" />
              </button>
            </div>
          </div>
          <div className="mt-4 flex flex-wrap justify-center gap-4 text-[10px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest">
            {["Sustainable Iceland", "Budget Rome", "Kyoto"].map(suggestion => (
              <button key={suggestion} type="button" onClick={() => setDestination(suggestion)} className="hover:text-indigo-600 dark:hover:text-indigo-400 transition-colors outline-none">
                {suggestion}
              </button>
            ))}
          </div>
        </form>

        <div className="max-w-4xl mx-auto relative px-2">
          <div className="bg-slate-50/50 dark:bg-slate-900/30 rounded-2xl p-4 md:p-8 border border-slate-100 dark:border-slate-800">
             <div className="flex flex-col md:flex-row gap-6 items-center text-left">
