                  <div className="h-1.5 w-16 bg-indigo-600 rounded-full"></div>
                  <h4 className="text-xl font-bold dark:text-white leading-tight">Your AI workspace.</h4>
                  <p className="text-xs text-slate-500 dark:text-slate-400 font-medium leading-normal">Edit, drag, and swap. AI manages transit logic and opening hours for you.</p>
                </div>
                <div className="flex-1 w-full aspect-[16/9] rounded-xl overflow-hidden shadow-lg relative group">
                  <img src="https://images.unsplash.com/photo-1476514525535-07fb3b4ae5f1?auto=format&fit=crop&q=80&w=800" alt="Travel workspace" className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" />
                  <div className="absolute inset-0 bg-indigo-600/5 group-hover:bg-transparent transition-colors"></div>
                </div>
             </div>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Hero;
